external_knowledge:
- 'most seasoned players' refers to players with the highest total play time;
- 'conquered a multitude of challenges' refers to players who have completed more than 5 quests;
- 'vanquished' is a metaphor for completing quests;
- 'ultimate play time badges' refers to the maximum total play time for each player.

sql:
SELECT achievement_name, points
FROM achievements
ORDER BY points DESC;

SELECT player_id, unlock_date
FROM player_achievements
ORDER BY unlock_date DESC;

SELECT character_id, SUM(total_online_time) AS total_online_time_sum
FROM online_time
GROUP BY character_id;

SELECT COUNT(*) AS total_active_players
FROM players
WHERE status = 'active';
